import { extendZodWithOpenApi } from "@asteasolutions/zod-to-openapi";
import { z } from "zod";

extendZodWithOpenApi(z);

export { z };

import {
  OpenAPIRegistry,
  OpenApiGeneratorV3
} from "@asteasolutions/zod-to-openapi";
import { z } from "../lib/zodOpenapi.js";
import {
  signupBodySchema,
  loginBodySchema,
  forgotPasswordBodySchema,
  resetPasswordBodySchema
} from "../modules/auth/schemas.js";
import {
  createProgramBodySchema,
  updateProgramBodySchema
} from "../modules/programs/schemas.js";
import {
  createSessionBodySchema,
  reorderSessionsBodySchema,
  updateSessionBodySchema
} from "../modules/sessions/schemas.js";
import { presignBodySchema } from "../modules/uploads/schemas.js";
import { importSessionsBodySchema } from "../modules/import/schemas.js";
import { auditQuerySchema } from "../modules/audit/schemas.js";

const CreatorPublicSchema = z
  .object({
    id: z.string(),
    email: z.string().email()
  })
  .openapi("CreatorPublic");

const AuthTokenResponseSchema = z
  .object({
    accessToken: z.string(),
    creator: CreatorPublicSchema
  })
  .openapi("AuthTokenResponse");

const ForgotPasswordAcceptedSchema = z
  .object({ ok: z.literal(true) })
  .openapi("ForgotPasswordAccepted");

const OkTrueSchema = z.object({ ok: z.literal(true) }).openapi("OkTrue");

const ErrorBodySchema = z
  .object({
    error: z.string(),
    message: z.string(),
    requestId: z.string().optional()
  })
  .openapi("ErrorBody");

const ProgramSchema = z
  .object({
    id: z.string(),
    tenantId: z.string(),
    title: z.string(),
    description: z.string().nullable(),
    createdAt: z.union([z.string(), z.number()]).openapi({
      description: "ISO datetime string when serialized via JSON"
    }),
    updatedAt: z.union([z.string(), z.number()]).openapi({
      description: "ISO datetime string when serialized via JSON"
    })
  })
  .openapi("Program");

const ProgramListSchema = z
  .object({ programs: z.array(ProgramSchema) })
  .openapi("ProgramList");

const SessionSchema = z
  .object({
    id: z.string(),
    tenantId: z.string(),
    programId: z.string(),
    title: z.string(),
    durationSeconds: z.number(),
    position: z.number(),
    instructorName: z.string(),
    tags: z.array(z.string()),
    mediaUrl: z.string().nullable(),
    mediaType: z.string().nullable(),
    createdAt: z.union([z.string(), z.number()]),
    updatedAt: z.union([z.string(), z.number()])
  })
  .openapi("Session");

const SessionListWrapperSchema = z
  .object({ sessions: z.array(SessionSchema) })
  .openapi("SessionList");

const PresignResponseSchema = z
  .object({
    uploadUrl: z.string().url(),
    key: z.string(),
    bucket: z.string(),
    expiresIn: z.number(),
    contentType: z.string(),
    publicUrl: z.string()
  })
  .openapi("PresignResponse");

const ImportRowResultSchema = z
  .discriminatedUnion("ok", [
    z.object({
      clientRowId: z.string(),
      ok: z.literal(true),
      sessionId: z.string(),
      idempotent: z.boolean().optional()
    }),
    z.object({
      clientRowId: z.string(),
      ok: z.literal(false),
      errors: z.array(z.string())
    })
  ])
  .openapi("ImportRowResult");

const ImportSessionsResponseSchema = z
  .object({
    clientImportId: z.string(),
    results: z.array(ImportRowResultSchema)
  })
  .openapi("ImportSessionsResponse");

const AuditLogSchema = z
  .object({
    id: z.string(),
    tenantId: z.string(),
    actorId: z.string(),
    action: z.string(),
    targetType: z.string(),
    targetId: z.string().nullable(),
    metadata: z.unknown().nullable(),
    createdAt: z.union([z.string(), z.number()])
  })
  .openapi("AuditLog");

const AuditListSchema = z
  .object({ auditLogs: z.array(AuditLogSchema) })
  .openapi("AuditLogList");

const HealthSchema = z.object({ ok: z.literal(true) }).openapi("Health");

function errorRefs(
  statuses: Record<number | string, { description: string }>
): Record<number | string, { description: string; content?: unknown }> {
  const base = [401, 403, 404, 409, 500, 503] as const;
  const merged: Record<string, { description: string; content: unknown }> = {
    ...statuses
  };
  for (const code of base) {
    const key = String(code);
    if (!merged[key]) {
      merged[key] = {
        description: HTTP_STATUS_TEXT[code] ?? `${code}`,
        content: errorContent
      };
    }
  }
  return merged as Record<number | string, { description: string; content?: unknown }>;
}

const errorContent = {
  "application/json": {
    schema: ErrorBodySchema
  }
};

const HTTP_STATUS_TEXT: Partial<Record<number, string>> = {
  400: "Validation or bad request",
  401: "Unauthorized",
  403: "Forbidden",
  404: "Not found",
  409: "Conflict",
  500: "Internal error",
  503: "Service unavailable"
};

export function buildOpenApiDocument(): ReturnType<
  OpenApiGeneratorV3["generateDocument"]
> {
  const registry = new OpenAPIRegistry();

  registry.registerComponent("securitySchemes", "bearerAuth", {
    type: "http",
    scheme: "bearer",
    bearerFormat: "JWT",
    description: "HS256 JWT; `sub` is the creator id (tenant)."
  });

  registry.registerPath({
    method: "get",
    path: "/health",
    tags: ["System"],
    security: [],
    summary: "Liveness probe",
    responses: {
      200: {
        description: "Service is reachable",
        content: { "application/json": { schema: HealthSchema } }
      }
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/auth/signup",
    tags: ["Auth"],
    security: [],
    summary: "Register a creator account",
    request: {
      body: {
        content: { "application/json": { schema: signupBodySchema } }
      }
    },
    responses: {
      ...errorRefs({
        201: {
          description: "Registered; returns bearer token",
          content: {
            "application/json": {
              schema: AuthTokenResponseSchema
            }
          }
        },
        409: {
          description: "Email already registered",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/auth/login",
    tags: ["Auth"],
    security: [],
    summary: "Login",
    request: {
      body: {
        content: { "application/json": { schema: loginBodySchema } }
      }
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Access token issued",
          content: {
            "application/json": {
              schema: AuthTokenResponseSchema
            }
          }
        },
        401: {
          description: "Invalid credentials",
          content: errorContent as never
        },
        503: {
          description: "JWT not configured",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/auth/forgot-password",
    tags: ["Auth"],
    security: [],
    summary: "Request password reset email (always succeeds shape)",
    request: {
      body: {
        content: {
          "application/json": { schema: forgotPasswordBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        202: {
          description: "Request accepted",
          content: {
            "application/json": {
              schema: ForgotPasswordAcceptedSchema
            }
          }
        },
        400: {
          description: "Validation error",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/auth/reset-password",
    tags: ["Auth"],
    security: [],
    summary: "Complete reset with emailed token",
    request: {
      body: {
        content: {
          "application/json": { schema: resetPasswordBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Password updated",
          content: {
            "application/json": {
              schema: AuthTokenResponseSchema
            }
          }
        },
        401: {
          description: "Invalid or expired token",
          content: errorContent as never
        },
        503: {
          description: "JWT not configured",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "get",
    path: "/v1/auth/me",
    tags: ["Auth"],
    summary: "Current creator profile",
    responses: {
      ...errorRefs({
        200: {
          description: "Creator identity",
          content: {
            "application/json": {
              schema: CreatorPublicSchema
            }
          }
        }
      })
    }
  });

  registry.registerPath({
    method: "get",
    path: "/v1/programs",
    tags: ["Programs"],
    summary: "List programs for authenticated tenant",
    responses: {
      ...errorRefs({
        200: {
          description: "Programs ordered by persistence default",
          content: {
            "application/json": { schema: ProgramListSchema }
          }
        }
      })
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/programs",
    tags: ["Programs"],
    summary: "Create program",
    request: {
      body: {
        content: {
          "application/json": { schema: createProgramBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        201: {
          description: "Created program",
          content: { "application/json": { schema: ProgramSchema } }
        },
        400: {
          description: "Validation error",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "get",
    path: "/v1/programs/{id}",
    tags: ["Programs"],
    summary: "Get program by id",
    request: {
      params: z.object({ id: z.string().min(1) })
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Program detail",
          content: { "application/json": { schema: ProgramSchema } }
        },
        404: {
          description: "Program not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "patch",
    path: "/v1/programs/{id}",
    tags: ["Programs"],
    summary: "Update program",
    request: {
      params: z.object({ id: z.string().min(1) }),
      body: {
        content: {
          "application/json": { schema: updateProgramBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Updated program",
          content: { "application/json": { schema: ProgramSchema } }
        },
        400: {
          description: "Validation error",
          content: errorContent as never
        },
        404: {
          description: "Program not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "delete",
    path: "/v1/programs/{id}",
    tags: ["Programs"],
    summary: "Delete program",
    request: {
      params: z.object({ id: z.string().min(1) })
    },
    responses: {
      ...errorRefs({
        204: { description: "Deleted" },
        404: {
          description: "Program not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "get",
    path: "/v1/sessions",
    tags: ["Sessions"],
    summary: "List sessions in a program",
    request: {
      query: z.object({
        programId: z
          .string()
          .min(1)
          .openapi({
            description: "Program id owned by tenant",
            param: {
              style: "form",
              in: "query"
            }
          })
      })
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Ordered sessions",
          content: {
            "application/json": { schema: SessionListWrapperSchema }
          }
        },
        400: {
          description: "Missing or invalid query",
          content: errorContent as never
        },
        404: {
          description: "Program not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/sessions/reorder",
    tags: ["Sessions"],
    summary: "Reorder sessions within a program",
    request: {
      body: {
        content: {
          "application/json": { schema: reorderSessionsBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Sessions after reorder",
          content: {
            "application/json": { schema: SessionListWrapperSchema }
          }
        },
        400: {
          description: "Validation or ordering constraint",
          content: errorContent as never
        },
        404: {
          description: "Program not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/sessions",
    tags: ["Sessions"],
    summary: "Create session",
    request: {
      body: {
        content: {
          "application/json": { schema: createSessionBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        201: {
          description: "Created session",
          content: { "application/json": { schema: SessionSchema } }
        },
        400: {
          description: "Validation error",
          content: errorContent as never
        },
        404: {
          description: "Program not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "get",
    path: "/v1/sessions/{id}",
    tags: ["Sessions"],
    summary: "Get session by id",
    request: {
      params: z.object({ id: z.string().min(1) })
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Session detail",
          content: { "application/json": { schema: SessionSchema } }
        },
        404: {
          description: "Session not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "patch",
    path: "/v1/sessions/{id}",
    tags: ["Sessions"],
    summary: "Update session",
    request: {
      params: z.object({ id: z.string().min(1) }),
      body: {
        content: {
          "application/json": { schema: updateSessionBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Updated session",
          content: { "application/json": { schema: SessionSchema } }
        },
        400: {
          description: "Validation error",
          content: errorContent as never
        },
        404: {
          description: "Session not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "delete",
    path: "/v1/sessions/{id}",
    tags: ["Sessions"],
    summary: "Delete session",
    request: {
      params: z.object({ id: z.string().min(1) })
    },
    responses: {
      ...errorRefs({
        204: { description: "Deleted" },
        404: {
          description: "Session not found for tenant",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/uploads/presign",
    tags: ["Uploads"],
    summary: "Presign PUT to tenant-scoped S3 key",
    request: {
      body: {
        content: {
          "application/json": { schema: presignBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        201: {
          description: "Presigned PUT URL issued",
          content: {
            "application/json": { schema: PresignResponseSchema }
          }
        },
        400: {
          description: "Invalid content type or body",
          content: errorContent as never
        },
        503: {
          description: "S3 not configured",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/import/sessions",
    tags: ["Import"],
    summary: "CSV bulk import (idempotent per client_import_id / client_row_id)",
    request: {
      body: {
        content: {
          "application/json": { schema: importSessionsBodySchema }
        }
      }
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Per-row outcomes",
          content: {
            "application/json": { schema: ImportSessionsResponseSchema }
          }
        },
        400: {
          description: "CSV or validation failures",
          content: errorContent as never
        }
      })
    }
  });

  registry.registerPath({
    method: "get",
    path: "/v1/audit",
    tags: ["Audit"],
    summary: "List audit log entries",
    request: {
      query: auditQuerySchema
    },
    responses: {
      ...errorRefs({
        200: {
          description: "Recent audit logs (bounded)",
          content: {
            "application/json": { schema: AuditListSchema }
          }
        },
        400: {
          description: "Invalid filter values",
          content: errorContent as never
        }
      })
    }
  });

  const generator = new OpenApiGeneratorV3(registry.definitions);

  return generator.generateDocument({
    openapi: "3.0.0",
    info: {
      title: "Wellspring API",
      version: "1.0.0",
      description:
        "Multi-tenant CMS API for wellness creators. Public routes omit Bearer auth; tenant scope is enforced from JWT `sub` on protected routes."
    },
    servers: [{ url: "/" }],
    tags: [
      { name: "System" },
      { name: "Auth" },
      { name: "Programs" },
      { name: "Sessions" },
      { name: "Uploads" },
      { name: "Import" },
      { name: "Audit" }
    ],
    security: [{ bearerAuth: [] }]
  });
}

import {
  OpenAPIRegistry,
  OpenApiGeneratorV3,
  type ResponseConfig
} from "@asteasolutions/zod-to-openapi";
import { z } from "../lib/zodOpenapi.js";
import {
  signupBodySchema,
  loginBodySchema,
  forgotPasswordBodySchema,
  resetPasswordBodySchema
} from "../modules/auth/schemas.js";
import {
  createProgramBodySchema,
  updateProgramBodySchema
} from "../modules/programs/schemas.js";
import {
  createSessionBodySchema,
  reorderSessionsBodySchema,
  updateSessionBodySchema
} from "../modules/sessions/schemas.js";
import { presignBodySchema } from "../modules/uploads/schemas.js";
import { importSessionsBodySchema } from "../modules/import/schemas.js";
import { auditQuerySchema } from "../modules/audit/schemas.js";

const CreatorPublicSchema = z
  .object({
    id: z.string(),
    email: z.string().email()
  })
  .openapi("CreatorPublic");

const AuthTokenResponseSchema = z
  .object({
    accessToken: z.string(),
    creator: CreatorPublicSchema
  })
  .openapi("AuthTokenResponse");

const ForgotPasswordAcceptedSchema = z
  .object({ ok: z.literal(true) })
  .openapi("ForgotPasswordAccepted");

const ErrorBodySchema = z
  .object({
    error: z.string(),
    message: z.string(),
    requestId: z.string().optional()
  })
  .openapi("ErrorBody");

function err(description: string): ResponseConfig {
  return {
    description,
    content: {
      "application/json": {
        schema: ErrorBodySchema
      }
    }
  };
}

const ProgramSchema = z
  .object({
    id: z.string(),
    tenantId: z.string(),
    title: z.string(),
    description: z.string().nullable(),
    createdAt: z.union([z.string(), z.number()]).openapi({
      description: "ISO datetime string after JSON serialization"
    }),
    updatedAt: z.union([z.string(), z.number()])
  })
  .openapi("Program");

const ProgramListSchema = z
  .object({ programs: z.array(ProgramSchema) })
  .openapi("ProgramList");

const SessionSchema = z
  .object({
    id: z.string(),
    tenantId: z.string(),
    programId: z.string(),
    title: z.string(),
    durationSeconds: z.number(),
    position: z.number(),
    instructorName: z.string(),
    tags: z.array(z.string()),
    mediaUrl: z.string().nullable(),
    mediaType: z.string().nullable(),
    createdAt: z.union([z.string(), z.number()]),
    updatedAt: z.union([z.string(), z.number()])
  })
  .openapi("Session");

const SessionListWrapperSchema = z
  .object({ sessions: z.array(SessionSchema) })
  .openapi("SessionList");

const PresignResponseSchema = z
  .object({
    uploadUrl: z.string(),
    key: z.string(),
    bucket: z.string(),
    expiresIn: z.number(),
    contentType: z.string(),
    publicUrl: z.string()
  })
  .openapi("PresignResponse");

const ImportRowOkSchema = z.object({
  clientRowId: z.string(),
  ok: z.literal(true),
  sessionId: z.string(),
  idempotent: z.boolean().optional()
});

const ImportRowErrSchema = z.object({
  clientRowId: z.string(),
  ok: z.literal(false),
  errors: z.array(z.string())
});

const ImportRowResultSchema = z
  .union([ImportRowOkSchema, ImportRowErrSchema])
  .openapi("ImportRowResult");

const ImportSessionsResponseSchema = z
  .object({
    clientImportId: z.string(),
    results: z.array(ImportRowResultSchema)
  })
  .openapi("ImportSessionsResponse");

const AuditLogSchema = z
  .object({
    id: z.string(),
    tenantId: z.string(),
    actorId: z.string(),
    action: z.string(),
    targetType: z.string(),
    targetId: z.string().nullable(),
    metadata: z.unknown().nullable(),
    createdAt: z.union([z.string(), z.number()])
  })
  .openapi("AuditLog");

const AuditListSchema = z
  .object({ auditLogs: z.array(AuditLogSchema) })
  .openapi("AuditLogList");

const HealthSchema = z.object({ ok: z.literal(true) }).openapi("Health");

const jsonOk = (
  schema: z.ZodType,
  description: string = "Successful response"
): ResponseConfig => ({
  description,
  content: { "application/json": { schema } }
});

const bearer401 = err("Unauthorized: missing or invalid Bearer token");

export function buildOpenApiDocument(): ReturnType<
  OpenApiGeneratorV3["generateDocument"]
> {
  const registry = new OpenAPIRegistry();

  registry.registerComponent("securitySchemes", "bearerAuth", {
    type: "http",
    scheme: "bearer",
    bearerFormat: "JWT",
    description: "HS256 JWT; `sub` is the creator id (tenant)."
  });

  registry.registerPath({
    method: "get",
    path: "/health",
    tags: ["System"],
    security: [],
    summary: "Liveness probe",
    responses: {
      200: jsonOk(HealthSchema, "Service is reachable")
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/auth/signup",
    tags: ["Auth"],
    security: [],
    summary: "Register a creator account",
    request: {
      body: {
        content: { "application/json": { schema: signupBodySchema } }
      }
    },
    responses: {
      201: jsonOk(AuthTokenResponseSchema, "Registered; returns bearer token"),
      400: err("Validation error"),
      409: err("Email already registered"),
      503: err("JWT_SECRET not configured")
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/auth/login",
    tags: ["Auth"],
    security: [],
    summary: "Login",
    request: {
      body: {
        content: { "application/json": { schema: loginBodySchema } }
      }
    },
    responses: {
      200: jsonOk(AuthTokenResponseSchema, "Access token issued"),
      400: err("Validation error"),
      401: err("Invalid email or password"),
      503: err("JWT_SECRET not configured")
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/auth/forgot-password",
    tags: ["Auth"],
    security: [],
    summary: "Request password reset email (opaque success shape)",
    request: {
      body: {
        content: {
          "application/json": { schema: forgotPasswordBodySchema }
        }
      }
    },
    responses: {
      202: jsonOk(ForgotPasswordAcceptedSchema, "Request accepted"),
      400: err("Validation error")
    }
  });

  registry.registerPath({
    method: "post",
    path: "/v1/auth/reset-password",
    tags: ["Auth"],
    security: [],
    summary: "Complete reset with emailed token",
    request: {
      body: {
        content: {
          "application/json": { schema: resetPasswordBodySchema }
        }
      }
    },
    responses: {
